def round_robin_scheduler(threads, time_quantum):
    ready_queue = [(t, bt) for t, bt in threads]  # (thread_id, burst_time)
    completed = {}
    current_time = 0

    while ready_queue:
        thread_id, burst = ready_queue.pop(0)

        if burst <= time_quantum:
            # Thread completes
            current_time += burst
            completed[thread_id] = {
                'finish': current_time,
                'turnaround': current_time  # Assuming arrival at 0
            }
        else:
            # Quantum expires, preempt
            current_time += time_quantum
            remaining = burst - time_quantum
            ready_queue.append((thread_id, remaining))

    return completed

# Example usage
threads = [('T1', 10), ('T2', 5), ('T3', 8)]
quantum = 4
result = round_robin_scheduler(threads, quantum)

def sjf_scheduler(threads):
    # threads: list of (thread_id, burst_time)
    # Sort by burst time (shortest first)
    sorted_threads = sorted(threads, key=lambda x: x[1])

    current_time = 0
    completion_times = {}
    turnaround_times = {}
    waiting_times = {}

    for thread_id, burst in sorted_threads:
        # Wait time is current time (time spent waiting before execution)
        waiting_times[thread_id] = current_time
        current_time += burst
        completion_times[thread_id] = current_time
        turnaround_times[thread_id] = current_time  # arrival assumed 0

    return {
        'completion': completion_times,
        'turnaround': turnaround_times,
        'waiting': waiting_times
    }

# Example usage
threads = [('T1', 6), ('T2', 8), ('T3', 7), ('T4', 3)]
result = sjf_scheduler(threads)

#include <pthread.h>
#include <stdio.h>
#include <unistd.h>

// Thread function
void* thread_function(void* arg) {
    int thread_id = *(int*)arg;
    printf("Thread %d started on CPU %d\n", thread_id, sched_getcpu());

    for (int i = 0; i < 5; i++) {
        printf("Thread %d: iteration %d\n", thread_id, i);
        sleep(1);  // Simulate work
    }

    printf("Thread %d completed\n", thread_id);
    return NULL;
}

int main() {
    pthread_t threads[4];
    int thread_ids[4] = {1, 2, 3, 4};

    // Set thread scheduling policy and priority
    struct sched_param param;
    param.sched_priority = 10;

    // Create threads
    for (int i = 0; i < 4; i++) {
        pthread_create(&threads[i], NULL, thread_function, &thread_ids[i]);
        pthread_setschedparam(threads[i], SCHED_FIFO, &param);
    }

    // Wait for all threads
    for (int i = 0; i < 4; i++) {
        pthread_join(threads[i], NULL);
    }

    printf("All threads completed\n");
    return 0;
}
